chunks.content:
ase58(),
        poolSignature: pool.createSignature,
        burnSignature: pool.burnSignature,
        error: undefined,
      });
    }

    if (!existingPool) throw new Error("Pool id missing after pool creation");
    await program.methods
      .finalizeMigration(existingPool, new BN(coreAmount.toString()), new BN(withdrawnTokens.toString()))
      .accounts({ global: globalPda, curve: curvePublicKey, migrationAuthority: config.authority.publicKey })
      .rpc();
    await store.patch(key, { phase: "finalized", error: undefined });
  } catch (error) {
    await store.patch(key, {
      phase: "failed",
      error: error instanceof Error ? error.stack ?? error.message : String(error),
    });
    throw error;
  }
}

import { AnchorProvider, Idl, Program, Wallet } from "@coral-xyz/anchor";
import { Connection, PublicKey } from "@solana/web3.js";
import { config } from "./config.js";
import idl from "./idl/core_launchpad.json" with { type: "json" };

export const connection = new Connection(config.rpcUrl, "confirmed");
export const provider = new AnchorProvider(connection, new Wallet(config.authority), { commitment: "confirmed" });
export const program = new Program({ ...(idl as Idl), address: config.programId.toBase58() }, provider);

export const globalPda = PublicKey.findProgramAddressSync([Buffer.from("global")], config.programId)[0];

export type CurveData = {
  mint: PublicKey;
  tokenVault: PublicKey;
  migrationAuthority: PublicKey;
  status: number;
  realSolReserves: { toString(): string };
  realTokenReserves: { toString(): string };
  migrationTokenReserves: { toString(): string };
  withdrawnSolAmount: { toString(): string };
  withdrawnTokenAmount: { toString(): string };
};

export async function fetchActionableCurves(): Promise<Array<{ publicKey: PublicKey; account: CurveData }>> {
  const rows = await (program.account as any).curve.all();
  return rows.filter((row: any) =>
    [1, 2, 3].includes(row.account.status) &&
    row.account.migrationAuthority.equals(config.authority.publicKey),
  );
}

export async function validateGlobalConfig(): Promise<void> {
  const global = await (program.account as any).globalConfig.fetch(globalPda);
  if (!global.coreMint.equals(config.coreMint)) {
    throw new Error(`CORE_MINT ${config.coreMint.toBase58()} does not match on-chain global config ${global.coreMint.toBase58()}`);
  }
}

import BN from "bn.js";
import {
  CREATE_CPMM_POOL_FEE_ACC,
  CREATE_CPMM_POOL_PROGRAM,
  Raydium,
  TxVersion,
} from "@raydium-io/raydium-sdk-v2";
import {
  createBurnInstruction,
  getAssociatedTokenAddressSync,
  getAccount,
  getMint,
} from "@solana/spl-token";
import { PublicKey, sendAndConfirmTransaction, Transaction } from "@solana/web3.js";
import { config } from "./config.js";
import { connection } from "./program.js";

let raydiumPromise: Promise<Raydium> | undefined;
function getRaydium(): Promise<Raydium> {
  raydiumPromise ??= Raydium.load({
    owner: config.authority,
    connection,
    cluster: "mainnet",
    disableFeatureCheck: true,
    blockhashCommitment: "confirmed",
  });
  return raydiumPromise!;
}

async function mintInfo(mint: PublicKey) {
  const account = await connection.getAccountInfo(mint, "confirmed");
  if (!account) throw new Error(`Mint ${mint.toBase58()} does not exist`);
  const parsed = await getMint(connection, mint, "confirmed", account.owner);
  return {
    address: mint.toBase58(),
    programId: account.owner.toBase58(),
    decimals: parsed.decimals,
  };
}

async function burnLp(lpMint: PublicKey): Promise<{ burnSignature: string; lpAmount: bigint }> {
  const lpAta = getAssociatedTokenAddressSync(lpMint, config.authority.publicKey);
  const lpAccount = await getAccount(connection, lpAta, "confirmed");
  const lpAmount = lpAccount.amount;
  if (lpAmount === 0n) return { burnSignature: "already-burned", lpAmount };

  const burnTx = new Transaction().add(
    createBurnInstruction(lpAta, lpMint, config.authority.publicKey, lpAmount),
  );
  const burnSignature = await sendAndConfirmTransaction(connection, burnTx, [config.authority], {
    commitment: "confirmed",
  });
  return { burnSignature, lpAmount };
}

export async function resumeAndBurnCorePool(poolId: PublicKey): Promise<{ burnSignature: string; lpAmount: bigint }> {
  const raydium = await getRaydium();
  const { poolInfo } = await raydium.cpmm.getPoolInfoFromRpc(poolId.toBase58());
  return burnLp(new PublicKey(poolInfo.lpMint.address));
}

export async function createAndBurnCorePool(args: {
  launchMint: PublicKey;
  launchTokenAmount: bigint;
  coreAmount: bigint;
  onPrepared?: (poolId: string) => Promise<void>;
}): Promise<{ poolId: PublicKey; createSignature: string; burnSignature: string; lpAmount: bigint }> {
  const raydium = await getRaydium();
  // Build mint metadata directly from chain. This avoids depending on either
  // token being present in Raydium's public token list.
  const [launchMintInfo, coreMintInfo, feeConfigs] = await Promise.all([
    mintInfo(args.launchMint),
    mintInfo(config.coreMint),
    raydium.api.getCpmmConfigs(),
  ]);
  const feeConfig = feeConfigs.find((entry: { index: number }) => entry.index === config.raydiumFeeConfigIndex);
  if (!feeConfig) throw new Error(`Raydium fee config ${config.raydiumFeeConfigIndex} not found`);

  const { execute, extInfo } = await raydium.cpmm.createPool({
    programId: CREATE_CPMM_POOL_PROGRAM,
    poolFeeAccount: CREATE_CPMM_POOL_FEE_ACC,
    mintA: launchMintInfo,
    mintB: coreMintInfo,
    mintAAmount: new BN(args.launchTokenAmount.toString()),
    mintBAmount: new BN(args.coreAmount.toString()),
    startTime: new BN(0),
    feeConfig,
    associatedOnly: false,
    ownerInfo: { useSOLBalance: false },
    txVersion: TxVersion.V0,
  });
  const poolId = extInfo.address.poolId;
  await args.onPrepared?.(poolId.toBase58());
  const { txId } = await

execute({ sendAndConfirm: true });
  const burned = await burnLp(extInfo.address.lpMint);
  return {
    poolId,
    createSignature: txId,
    burnSignature: burned.burnSignature,
    lpAmount: burned.lpAmount,
  };
}
